package ir.tahamohamadi.skill; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*;
@Entity @Table(name="skill_category_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class SkillCategoryTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="skill_category_id",nullable=false) private SkillCategory category; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String name; @Column(columnDefinition="text") private String description; }
